const raw = items[0]?.json || {};
const event = raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body) ? raw.body : raw;
const payload = event.payload && typeof event.payload === 'object' && !Array.isArray(event.payload) ? event.payload : event;
const queueStage = event.current_stage || event.queue_stage || event.stage || payload.current_stage || payload.queue_stage || payload.stage || '';
if (queueStage !== 'Ready for Planning') {
  throw new Error(`AI3 planning intake accepts only the 'Ready for Planning' queue stage. Received: ${queueStage || 'missing'}`);
}
const taskId = payload.task_id || payload.id || event.task_id || event.id;
const title = payload.title || event.title;
const description = payload.description || event.description;
if (!taskId) throw new Error('Missing task_id');
if (!title) throw new Error('Missing title');
if (!description) throw new Error('Missing description');
return [{
  json: {
    meta: {
      workflow_name: 'AI3_Planning_Intake',
      timestamp: new Date().toISOString(),
      trigger_source: event.trigger_source || raw.trigger_source || 'queue_status_webhook',
      risk_level: event.risk_level || raw.risk_level || 'medium'
    },
    context: {
      canonical_links: [
        event.queue_link || '[[04-Tasks/Workflow-Queue|Workflow Queue]]',
        ...(Array.isArray(payload.product_context_links) ? payload.product_context_links : [])
      ],
      constraints: [
        'Do not invent compliance truth',
        ...(Array.isArray(event.constraints) ? event.constraints : [])
      ]
    },
    payload: {
      task_id: taskId,
      title,
      description,
      requested_by: payload.requested_by || event.requested_by || 'Owner',
      complexity: payload.complexity || event.complexity || 'non-trivial',
      external_dependency: Boolean(payload.external_dependency ?? event.external_dependency ?? false),
      product_context_links: Array.isArray(payload.product_context_links) ? payload.product_context_links : [],
      known_constraints: Array.isArray(payload.known_constraints) ? payload.known_constraints : [],
      priority: payload.priority || event.priority || 'medium'
    }
  }
}];

const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'task_id', 'status', 'escalate_to', 'reason', 'plan_skeleton'];
for (const key of required) {
  if (!(key in item)) {
    throw new Error(`Missing required key: ${key}`);
  }
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) {
  throw new Error(`Invalid status: ${item.status}`);
}
const allowedEscalation = new Set(['none', 'AI-1', 'AI-2', 'AI-3', 'AI-5', 'AI-6', 'AI-7', 'AI-8', 'AI-9', 'AI-10', 'AI-11', 'Owner']);
if (!allowedEscalation.has(item.escalate_to)) {
  throw new Error(`Invalid escalate_to: ${item.escalate_to}`);
}
item.execution_action = item.escalate_to !== 'none' ? 'create_handoff_or_escalation' : 'write_plan_shell_and_queue_update';
item.queue_stage = 'Ready for Planning';
return [{ json: item }];
